title: $:/plugins/wikilabs/devtools/startup.js
type: application/javascript
module-type: startup

Source position tracking plugin. Adds data-source-pos attributes to rendered
HTML elements and links, tracing each back to its source tiddler and line range.

All tracking logic lives in this plugin — no core modifications required.
Uses th-dom-rendering-element and th-dom-rendering-link hooks for elements/links,
and monkey-patches the transclude widget to set sourceContext for tiddler attribution.

\*/

"use strict";

var sourcePosUtils = require("$:/plugins/wikilabs/devtools/utils.js");

exports.name = "sourcepos";
exports.before = ["startup"];
exports.after = ["load-modules"];
exports.synchronous = true;

// Caches (reset on each tracking toggle to avoid stale data)
var lineCache = {};
var headerCache = {};
var bodyOffsetCache = {};

// Build array of line-start character offsets for a tiddler's text
function getLineOffsets(title) {
	if(lineCache[title]) return lineCache[title];
	var text = $tw.wiki.getTiddlerText(title, "");
	var offsets = [0];
	for(var i = 0; i < text.length; i++) {
		if(text.charAt(i) === "\n") offsets.push(i + 1);
	}
	lineCache[title] = offsets;
	return offsets;
}

// Binary search: character offset → 1-based line number
function charToLine(offsets, charPos) {
	var lo = 0, hi = offsets.length - 1;
	while(lo < hi) {
		var mid = (lo + hi + 1) >> 1;
		if(offsets[mid] <= charPos) lo = mid; else hi = mid - 1;
	}
	return lo + 1;
}

// Count .tid file header lines (fields excluding text + 1 blank separator)
function getTidHeaderLines(title) {
	if(headerCache[title] !== undefined) return headerCache[title];
	var tiddler = $tw.wiki.getTiddler(title);
	if(!tiddler) {
		headerCache[title] = 0;
		return 0;
	}
	// Exclude fields not written to .tid files: 'text' (body), 'bag' (excluded by
	// $:/core/templates/tid-tiddler), and 'revision' (sync adapter runtime field)
	var exclude = {"text": true, "bag": true, "revision": true};
	var fieldCount = 0;
	for(var f in tiddler.fields) {
		if(!exclude[f]) fieldCount++;
	}
	headerCache[title] = fieldCount + 1; // fields + empty line
	return headerCache[title];
}

// Find the character offset where a variable body starts within the full tiddler text
function findBodyOffset(title, bodyText) {
	var key = title + "\0" + bodyText.length;
	if(bodyOffsetCache[key] !== undefined) return bodyOffsetCache[key];
	var fullText = $tw.wiki.getTiddlerText(title, "");
	var idx = fullText.indexOf(bodyText);
	bodyOffsetCache[key] = idx >= 0 ? idx : 0;
	return bodyOffsetCache[key];
}

// Walk up the widget tree to find the nearest sourceContext
function getSourceInfo(widget) {
	var w = widget;
	while(w) {
		if(w.sourceContext !== undefined) {
			return { title: w.sourceContext, offset: w.sourceContextOffset || 0 };
		}
		w = w.parentWidget;
	}
	return null;
}

// Build the transclusion caller chain by walking up sourceContext changes.
// Stops at the first non-system tiddler to avoid showing TW's internal
// UI template chain ($:/core/ui/ViewTemplate, PageTemplate, etc.)
function buildCallerChain(widget) {
	var chain = [];
	var lastContext = null;
	var w = widget;
	while(w) {
		if(w.sourceContext !== undefined && w.sourceContext !== lastContext) {
			if(lastContext !== null) {
				chain.push(w.sourceContext);
			}
			lastContext = w.sourceContext;
		}
		w = w.parentWidget;
	}
	return chain;
}

// Build the data-source-pos value with line numbers: L{start}-L{end}@tiddlerTitle
function buildPosInfo(widget) {
	var ptn = widget.parseTreeNode;
	if(!ptn || ptn.start === undefined) {
		return null;
	}
	var info = getSourceInfo(widget);
	if(!info) {
		return null;
	}
	var offsets = getLineOffsets(info.title);
	var absStart = ptn.start + info.offset;
	var absEnd = (ptn.end || ptn.start) + info.offset;
	var startLine = charToLine(offsets, absStart);
	var endLine = charToLine(offsets, absEnd);
	var headerOffset = getTidHeaderLines(info.title);
	return sourcePosUtils.format(startLine + headerOffset, endLine + headerOffset, info.title);
}

exports.startup = function() {
	// --- Prototype patches for core widgets (no core modifications required) ---

	// Patch setVariable to store sourceTitle for variable-to-tiddler attribution
	var Widget = require("$:/core/modules/widgets/widget.js").widget;
	var origSetVariable = Widget.prototype.setVariable;
	Widget.prototype.setVariable = function(name, value, params, isMacroDefinition, options) {
		origSetVariable.call(this, name, value, params, isMacroDefinition, options);
		if(options && options.sourceTitle && this.variables[name]) {
			this.variables[name].sourceTitle = options.sourceTitle;
		}
	};

	// Patch importvariables to propagate sourceTitle through imported globals
	var ImportVariablesWidget = require("$:/core/modules/widgets/importvariables.js").importvariables;
	var origImportExecute = ImportVariablesWidget.prototype.execute;
	ImportVariablesWidget.prototype.execute = function(tiddlerList) {
		origImportExecute.call(this, tiddlerList);
		// Build map: variable name → source tiddler title
		var varSourceMap = Object.create(null);
		var self = this;
		$tw.utils.each(this.tiddlerList, function(title) {
			var parser = self.wiki.parseTiddler(title, {parseAsInline: true, configTrimWhiteSpace: false});
			if(parser) {
				var node = parser.tree[0];
				while(node && ["setvariable", "set", "parameters", "void"].indexOf(node.type) !== -1) {
					if(node.attributes && node.attributes.name) {
						varSourceMap[node.attributes.name.value] = title;
					}
					node = node.children && node.children[0];
				}
			}
		});
		// Walk the widget chain and tag variables that lack sourceTitle
		var ptr = this;
		while(ptr) {
			if(ptr.variables) {
				var ownKeys = Object.keys(ptr.variables);
				for(var ki = 0; ki < ownKeys.length; ki++) {
					var v = ptr.variables[ownKeys[ki]];
					if(v && !v.sourceTitle && varSourceMap[ownKeys[ki]]) {
						v.sourceTitle = varSourceMap[ownKeys[ki]];
					}
				}
			}
			ptr = (ptr.children && ptr.children.length === 1) ? ptr.children[0] : null;
		}
	};

	// Patch link widget to invoke th-dom-rendering-link hook
	var LinkWidget = require("$:/core/modules/widgets/link.js").link;
	var origRenderLink = LinkWidget.prototype.renderLink;
	LinkWidget.prototype.renderLink = function(parent, nextSibling) {
		origRenderLink.call(this, parent, nextSibling);
		if(this.domNodes.length > 0) {
			$tw.hooks.invokeHook("th-dom-rendering-link", this.domNodes[this.domNodes.length - 1], this);
		}
	};

	// Patch codeblock widget to invoke th-dom-rendering-codeblock hook
	var CodeBlockWidget = require("$:/core/modules/widgets/codeblock.js").codeblock;
	var origCodeBlockRender = CodeBlockWidget.prototype.render;
	CodeBlockWidget.prototype.render = function(parent, nextSibling) {
		origCodeBlockRender.call(this, parent, nextSibling);
		if(this.domNodes.length > 0) {
			$tw.hooks.invokeHook("th-dom-rendering-codeblock", this.domNodes[this.domNodes.length - 1], this);
		}
	};

	// --- Source position tracking setup ---

	// Set initial state from config
	updateTracking();
	// Watch for config changes
	$tw.wiki.addEventListener("change", function(changes) {
		if(changes["$:/config/wikilabs/SourcePositionTracking"]) {
			updateTracking();
		}
	});
	// Shared hook logic for elements and links
	var addSourcePos = function(domNode, widget) {
		if($tw.wiki.trackSourcePositions) {
			var posInfo = buildPosInfo(widget);
			if(posInfo) {
				domNode.setAttribute("data-source-pos", posInfo);
				// Store raw char positions for precise editor selection
				// Offset adjusts for macro body position within the tiddler text
				var ptn = widget.parseTreeNode;
				var srcInfo = getSourceInfo(widget);
				var charOffset = srcInfo ? srcInfo.offset : 0;
				if(ptn && ptn.start !== undefined) {
					domNode.setAttribute("data-source-start", ptn.start + charOffset);
					domNode.setAttribute("data-source-end", (ptn.end || ptn.start) + charOffset);
				}
				var callers = buildCallerChain(widget);
				// Add currentTiddler context so repeated list items can be distinguished
				var ct = widget.getVariable("currentTiddler");
				var info = getSourceInfo(widget);
				if(ct && info && ct !== info.title) {
					domNode.setAttribute("data-source-context", ct);
				}
				if(callers.length > 0) {
					domNode.setAttribute("data-source-caller", callers.map(function(c) { return "\u2190 " + c; }).join("\n"));
				}
			}
			// Store widget back-reference for variable inspection
			domNode._twWidget = widget;
		}
		return domNode;
	};
	// Hook: add data-source-pos to element DOM nodes
	$tw.hooks.addHook("th-dom-rendering-element", addSourcePos);
	// Hook: add data-source-pos to link DOM nodes
	$tw.hooks.addHook("th-dom-rendering-link", addSourcePos);
	// Hook: add data-source-pos to codeblock DOM nodes
	$tw.hooks.addHook("th-dom-rendering-codeblock", addSourcePos);
	// Monkey-patch transclude widget to set sourceContext for position attribution
	var TranscludeWidget = require("$:/core/modules/widgets/transclude.js").transclude;
	var origExecute = TranscludeWidget.prototype.execute;
	TranscludeWidget.prototype.execute = function() {
		origExecute.call(this);
		// Set source context after execute so transcludeTitle/transcludeVariable are resolved
		if($tw.wiki.trackSourcePositions) {
			// Check transcludeVariable first — when both $variable and $tiddler are set,
			// the parse tree comes from the variable definition, not the tiddler
			if(this.transcludeVariable) {
				var varInfo = this.getVariableInfo(this.transcludeVariable);
				var srcVar = varInfo && varInfo.srcVariable;
				this.sourceContext = (srcVar && srcVar.sourceTitle) || this.transcludeVariable;
				this.sourceContextOffset = 0;
				if(srcVar && srcVar.sourceTitle && srcVar.value) {
					this.sourceContextOffset = findBodyOffset(srcVar.sourceTitle, srcVar.value);
				}
			} else if(this.transcludeTitle) {
				this.sourceContext = this.transcludeTitle;
				this.sourceContextOffset = 0;
			}
		}
	};
};

function updateTracking() {
	var enabled = $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking", "no").trim() === "yes";
	$tw.wiki.trackSourcePositions = enabled;
	// Clear caches when tracking state changes
	if(enabled) {
		lineCache = {};
		headerCache = {};
		bodyOffsetCache = {};
	}
}
","type":"application/javascript","module-type":"startup"},"$:/plugins/wikilabs/devtools/utils.js":{"title":"$:/plugins/wikilabs/devtools/utils.js","text":"/*\
title: $:/plugins/wikilabs/devtools/utils.js
type: application/javascript
module-type: library

Shared utilities for source position formatting and parsing.
Single source of truth for the data-source-pos attribute format.

\*/

"use strict";

var SEPARATOR = " @ ";

// Format a source position into the data-source-pos attribute value
// Returns "L{start}-L{end} @ tiddlerTitle" or "L{start} @ tiddlerTitle" for single-line
exports.format = function(startLine, endLine, title) {
	var pos = (startLine === endLine) ? "L" + startLine : "L" + startLine + "-L" + endLine;
	if(title) {
		pos += SEPARATOR + title;
	}
	return pos;
};

// Parse a data-source-pos attribute value
// Returns { range: "L81-L84", tiddler: "$:/cards/procedures" } or null
exports.parse = function(posString) {
	if(!posString) return null;
	var idx = posString.indexOf(SEPARATOR);
	if(idx === -1) {
		return { range: posString, tiddler: null };
	}
	return {
		range: posString.slice(0, idx),
		tiddler: posString.slice(idx + SEPARATOR.length)
	};
};

// Parse a range string like "L81-L84" or "L8" into { startLine: 81, endLine: 84 }
exports.parseRange = function(rangeString) {
	if(!rangeString) return null;
	var match = rangeString.match(/^L(\d+)(?:-L(\d+))?$/);
	if(!match) return null;
	var start = parseInt(match[1], 10);
	return { startLine: start, endLine: match[2] ? parseInt(match[2], 10) : start };
};

exports.SEPARATOR = SEPARATOR;

// --- Sourcepos event bus ---
// Shared pub/sub for inter-panel communication that does NOT touch the TW store.
// This avoids triggering the TW refresh cycle (which closes popups, etc.)
// while still allowing panels to stay linked.

var bus = {
	_listeners: {},
	on: function(event, fn) {
		if(!bus._listeners[event]) bus._listeners[event] = [];
		bus._listeners[event].push(fn);
	},
	off: function(event, fn) {
		var list = bus._listeners[event];
		if(!list) return;
		var idx = list.indexOf(fn);
		if(idx !== -1) list.splice(idx, 1);
	},
	emit: function(event, data) {
		var list = bus._listeners[event];
		if(!list) return;
		for(var i = 0; i < list.length; i++) {
			list[i](data);
		}
	}
};

// Shared state (replaces $:/temp tiddlers)
var state = {
	inspectorFilter: "",
	inspectorLinked: true,
	openPreviews: {},
	colorIndex: 0,
	inspectorLayout: { width: 600, height: 350, left: NaN, top: NaN },
	viewerLayout: { width: 600, height: 400, left: -1, top: 60 }
};

exports.bus = bus;
exports.state = state;

// ── DOM helpers ──

// Create element with className and optional text
exports.el = function(tag, cls, text) {
	var e = document.createElement(tag);
	if(cls) e.className = cls;
	if(text) e.textContent = text;
	return e;
};

// Make an element draggable via a handle
// opts: { ignore(e), onStart(left,top), onEnd() }
exports.makeDraggable = function(handle, target, opts) {
	handle.addEventListener("mousedown", function(e) {
		if(opts.ignore && opts.ignore(e)) return;
		e.preventDefault();
		var startX = e.clientX, startY = e.clientY;
		var rect = target.getBoundingClientRect();
		var origLeft = rect.left, origTop = rect.top;
		if(opts.onStart) opts.onStart(origLeft, origTop);
		var onMove = function(me) {
			target.style.left = Math.max(0, origLeft + me.clientX - startX) + "px";
			target.style.top = Math.max(0, origTop + me.clientY - startY) + "px";
		};
		var onUp = function() {
			document.removeEventListener("mousemove", onMove);
			document.removeEventListener("mouseup", onUp);
			if(opts.onEnd) opts.onEnd();
		};
		document.addEventListener("mousemove", onMove);
		document.addEventListener("mouseup", onUp);
	});
};

// Make an element resizable via a handle
// opts: { minW, minH, onStart(), onEnd() }
exports.makeResizable = function(handle, target, opts) {
	handle.addEventListener("mousedown", function(e) {
		e.preventDefault();
		e.stopPropagation();
		if(opts.onStart) opts.onStart();
		var startX = e.clientX, startY = e.clientY;
		var origW = target.offsetWidth, origH = target.offsetHeight;
		var onMove = function(me) {
			target.style.width = Math.max(opts.minW || 300, origW + me.clientX - startX) + "px";
			target.style.height = Math.max(opts.minH || 150, origH + me.clientY - startY) + "px";
		};
		var onUp = function() {
			document.removeEventListener("mousemove", onMove);
			document.removeEventListener("mouseup", onUp);
			if(opts.onEnd) opts.onEnd();
		};
		document.addEventListener("mousemove", onMove);
		document.addEventListener("mouseup", onUp);
	});
};

// Icon HTML cache
var iconCache = {};
exports.getIconHTML = function(transclusion) {
	if(!iconCache[transclusion]) {
		iconCache[transclusion] = exports.renderIconHTML(transclusion);
	}
	return iconCache[transclusion];
};

// Create an icon button with SVG at given size
exports.makeIconBtn = function(cls, iconTransclusion, title, size) {
	var btn = exports.el("span", cls);
	btn.innerHTML = exports.getIconHTML(iconTransclusion);
	if(title) btn.title = title;
	var svg = btn.querySelector("svg");
	if(svg) { svg.setAttribute("width", size || "12px"); svg.setAttribute("height", size || "12px"); }
	return btn;
};

// Create an expandable preview panel
// getText: function returning content text
// opts: { anchor, expanded, tallFade, maxHeight, onToggle(exp), onRemove(), onShow() }
exports.makeExpandable = function(getText, opts) {
	var previewEl = null;
	var isExpanded = opts.expanded || false;
	var el = exports.el;

	function show(expanded) {
		previewEl = el("div", "wltc-preview");
		var pre = el("pre", "wltc-preview-code");
		pre.textContent = getText();
		var fade = el("div", opts.tallFade ? "wltc-preview-fade wltc-preview-fade-tall" : "wltc-preview-fade");
		previewEl.appendChild(pre);
		previewEl.appendChild(fade);
		var maxCollapsed = opts.maxHeight || "3.6em";
		function applyState(exp) {
			if(exp) {
				pre.style.maxHeight = "none";
				pre.style.overflow = "auto";
				fade.style.display = "none";
			} else {
				pre.style.maxHeight = maxCollapsed;
				pre.style.overflow = "hidden";
				requestAnimationFrame(function() {
					fade.style.display = pre.scrollHeight > pre.clientHeight ? "" : "none";
				});
			}
		}
		applyState(expanded);
		previewEl.title = "Click to expand/collapse";
		previewEl.addEventListener("click", function() {
			var nowExpanded = pre.style.maxHeight === "none";
			isExpanded = !nowExpanded;
			if(opts.onToggle) opts.onToggle(isExpanded);
			applyState(isExpanded);
		});
		opts.anchor.insertAdjacentElement("afterend", previewEl);
	}

	return {
		toggle: function() {
			if(previewEl) { previewEl.remove(); previewEl = null; if(opts.onRemove) opts.onRemove(); return; }
			show(isExpanded);
			if(opts.onShow) opts.onShow();
		},
		restore: function() { show(isExpanded); },
		isOpen: function() { return !!previewEl; }
	};
};

// Find nearest ancestor with data-source-pos and parse it
exports.findSourcePos = function(target) {
	var node = target;
	while(node && node !== document.body) {
		var pos = node.getAttribute && node.getAttribute("data-source-pos");
		if(pos) {
			var parsed = exports.parse(pos);
			if(parsed && parsed.tiddler) {
				return {
					element: node, raw: pos, range: parsed.range, tiddler: parsed.tiddler,
					charStart: parseInt(node.getAttribute("data-source-start"), 10),
					charEnd: parseInt(node.getAttribute("data-source-end"), 10),
					caller: node.getAttribute("data-source-caller") || null,
					context: node.getAttribute("data-source-context") || null
				};
			}
		}
		node = node.parentNode;
	}
	return null;
};

// Find the TiddlyWiki widget associated with a DOM element
exports.findWidget = function(target) {
	var node = target;
	while(node && node !== document.body) {
		if(node._twWidget) return node._twWidget;
		node = node.parentNode;
	}
	return null;
};

// Collect variables in scope by walking up the widget tree
exports.collectVariables = function(widget) {
	var seen = {}, vars = [], w = widget;
	while(w) {
		if(w.variables) {
			var keys = Object.keys(w.variables);
			for(var i = 0; i < keys.length; i++) {
				var name = keys[i];
				if(!seen[name]) {
					seen[name] = true;
					var v = w.variables[name];
					vars.push({
						name: name,
						value: v.value !== undefined ? v.value : (v.text !== undefined ? v.text : undefined),
						params: v.params || undefined,
						sourceTitle: v.sourceTitle || undefined,
						isMacro: v.isMacroDefinition || false,
						isProcedure: !!v.isProcedure || (v.configTrimWhiteSpace === true),
						isFunction: !!v.isFunctionDefinition,
						isWidget: !!v.isWidgetDefinition,
						_scopeWidget: widget
					});
				}
			}
		}
		w = w.parentWidget;
	}
	return vars;
};

// Render a wikitext transclusion safely using TW's widget system.
// TW's element widget already handles:
//   - Unsafe element blacklist ($tw.config.htmlUnsafeElements -> "safe-" prefix)
//   - Event attribute stripping (excludeEventAttributes: true in element.js)
// We only add javascript: URI stripping as an additional safety layer.
exports.renderIconHTML = function(transclusion) {
	var container = document.createElement("div");
	var parser = $tw.wiki.parseText("text/vnd.tiddlywiki", transclusion);
	var widgetNode = $tw.wiki.makeWidget(parser, {document: document});
	widgetNode.render(container, null);
	// Strip javascript: URIs — not covered by TW's element widget
	var allEls = container.getElementsByTagName("*");
	for(var i = 0; i < allEls.length; i++) {
		var attrs = allEls[i].attributes;
		for(var j = attrs.length - 1; j >= 0; j--) {
			if(/^(href|src|action|formaction)$/i.test(attrs[j].name) &&
				/^\s*javascript\s*:/i.test(attrs[j].value || "")) {
				allEls[i].removeAttribute(attrs[j].name);
			}
		}
	}
	return container.innerHTML;
};
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/click-handler.js":{"title":"$:/plugins/wikilabs/devtools/click-handler.js","text":"/*\
title: $:/plugins/wikilabs/devtools/click-handler.js
type: application/javascript
module-type: startup

Startup: registers event handlers for hover tooltip and context menu.
Patches TW's popup handler to ignore clicks inside devtools panels.

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var tooltip = require("$:/plugins/wikilabs/devtools/tooltip.js");
var contextMenu = require("$:/plugins/wikilabs/devtools/context-menu.js");

exports.name = "sourcepos-click";
exports.after = ["sourcepos"];
exports.platforms = ["browser"];
exports.synchronous = true;

exports.startup = function() {
	// Patch TW's popup handler to ignore clicks inside our panels
	var origHandleEvent = $tw.popup.handleEvent.bind($tw.popup);
	$tw.popup.handleEvent = function(event) {
		if(event.type === "click" && event.target.closest &&
			event.target.closest(".sourcepos-var-inspector, #sourcepos-source-viewer, #sourcepos-context-menu")) {
			return;
		}
		return origHandleEvent(event);
	};

	// Hover tooltip
	tooltip.setup();

	// Context menu on right-click
	document.addEventListener("contextmenu", function(event) {
		if(!$tw.wiki.trackSourcePositions || event.ctrlKey) return;
		var info = utils.findSourcePos(event.target);
		if(!info) return;
		contextMenu.show(event, info);
	}, true);
};
","type":"application/javascript","module-type":"startup"},"$:/plugins/wikilabs/devtools/context-menu.js":{"title":"$:/plugins/wikilabs/devtools/context-menu.js","text":"/*\
title: $:/plugins/wikilabs/devtools/context-menu.js
type: application/javascript
module-type: library

Context menu: right-click menu with copy, navigation, inspect, and edit actions.

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var sourceViewer = require("$:/plugins/wikilabs/devtools/source-viewer.js");
var variableInspector = require("$:/plugins/wikilabs/devtools/variable-inspector.js");
var inlineEditor = require("$:/plugins/wikilabs/devtools/inline-editor.js");
var el = utils.el;

function makeMenuItem(text, onClick) {
	var item = el("div", "wltc-menu-item", text);
	item.addEventListener("click", function(e) {
		e.stopPropagation();
		e.preventDefault();
		onClick(e);
	});
	return item;
}

// Open tiddler in edit mode and select source range
function editAndSelect(info, removeMenu) {
	var title = info.tiddler;
	var story = new $tw.Story();
	var tiddler = $tw.wiki.getTiddler(title);
	var draftTitle;
	if(tiddler && tiddler.fields["draft.of"]) {
		draftTitle = title;
	} else {
		draftTitle = $tw.wiki.findDraft(title);
		if(!draftTitle) {
			story.navigateTiddler(title);
			draftTitle = $tw.wiki.generateDraftTitle(title);
			$tw.wiki.addTiddler(new $tw.Tiddler(
				{text: ""}, tiddler,
				{ title: draftTitle, "draft.title": title, "draft.of": title },
				$tw.wiki.getModificationFields()
			));
			var storyList = story.getStoryList();
			var idx = storyList.indexOf(title);
			if(idx !== -1) { storyList[idx] = draftTitle; } else { storyList.unshift(draftTitle); }
			story.saveStoryList(storyList);
		}
	}
	var animDuration = parseInt($tw.wiki.getTiddlerText("$:/config/AnimationDuration", "400"), 10) || 400;
	var selectRange = function(retries) {
		var sel = "[data-tiddler-title=\"" + draftTitle.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\]/g, "\\]") + "\"]";
		var tiddlerEl = document.querySelector(sel);
		if(!tiddlerEl) { if(retries > 0) setTimeout(function() { selectRange(retries - 1); }, 200); return; }
		var textarea = null;
		var iframe = tiddlerEl.querySelector("iframe.tc-edit-texteditor-body") || tiddlerEl.querySelector("iframe.tc-edit-texteditor");
		if(iframe && iframe.contentDocument) textarea = iframe.contentDocument.querySelector("textarea");
		if(!textarea) textarea = tiddlerEl.querySelector("textarea.tc-edit-texteditor-body") || tiddlerEl.querySelector("textarea.tc-edit-texteditor");
		if(!textarea) { if(retries > 0) setTimeout(function() { selectRange(retries - 1); }, 200); return; }
		if(!textarea.value && retries > 0) { setTimeout(function() { selectRange(retries - 1); }, 200); return; }
		var startChar = isNaN(info.charStart) ? 0 : info.charStart;
		var endChar = isNaN(info.charEnd) ? 0 : info.charEnd;
		textarea.focus();
		textarea.setSelectionRange(startChar, endChar);
		var lineNumber = textarea.value.substring(0, startChar).split("\n").length;
		var ownerWindow = textarea.ownerDocument.defaultView || window;
		var lineHeight = parseFloat(ownerWindow.getComputedStyle(textarea).lineHeight) || 16;
		var editorEl = iframe || textarea;
		var selectionScreenY = editorEl.getBoundingClientRect().top + lineNumber * lineHeight;
		if(selectionScreenY < 0 || selectionScreenY > window.innerHeight) {
			window.scrollBy({ top: selectionScreenY - (window.innerHeight / 3), behavior: "instant" });
		}
	};
	setTimeout(function() { selectRange(5); }, animDuration + 100);
	if(removeMenu) removeMenu();
}

function show(event, info) {
	var existing = document.getElementById("sourcepos-context-menu");
	if(existing) existing.remove();
	event.preventDefault();

	var menu = el("div", "wltc-menu");
	menu.id = "sourcepos-context-menu";
	var closeMenu, closeOnEscape;
	var removeMenu = function() {
		menu.remove();
		document.removeEventListener("click", closeMenu, true);
		document.removeEventListener("keydown", closeOnEscape, true);
	};
	var menuX = event.clientX, menuY = event.clientY;
	var rangeInfo = utils.parseRange(info.range);

	// Header
	var header = el("div", "wltc-menu-header");
	header.appendChild(el("span", null, info.raw));

	if(rangeInfo) {
		var editBtn = utils.makeIconBtn("wltc-menu-btn-icon", "{{$:/core/images/edit-button}}", "Edit at " + info.range, "14px");
		editBtn.addEventListener("click", function() { editAndSelect(info, removeMenu); });
		header.appendChild(editBtn);

		var viewBtn = utils.makeIconBtn("wltc-menu-btn-icon", "{{$:/core/images/preview-open}}", "Show source", "14px");
		viewBtn.addEventListener("click", function() {
			sourceViewer.addEntry(info, function() { editAndSelect(info); });
			removeMenu();
		});
		header.appendChild(viewBtn);
	}

	var menuCloseBtn = el("span", "wltc-menu-btn", "\u2715");
	menuCloseBtn.addEventListener("click", function() { removeMenu(); });
	header.appendChild(menuCloseBtn);
	menu.appendChild(header);

	// Menu items
	menu.appendChild(makeMenuItem("Copy tiddler title", function() {
		navigator.clipboard.writeText(info.tiddler); removeMenu();
	}));
	menu.appendChild(makeMenuItem("Copy source position", function() {
		var text = info.raw;
		if(info.context) text += "  \u00BB " + info.context;
		if(info.caller) text += "\n" + info.caller;
		navigator.clipboard.writeText(text); removeMenu();
	}));

	var widget = utils.findWidget(event.target);
	if(widget) {
		menu.appendChild(makeMenuItem("Inspect variables", function() {
			var vars = utils.collectVariables(widget);
			removeMenu();
			variableInspector.show(vars, menuX, menuY, info.element, widget);
		}));
	}

	// Inline editor (hidden by default)
	if(!isNaN(info.charStart) && !isNaN(info.charEnd) && info.charEnd > info.charStart
		&& $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking/ShowEditInline", "").trim() === "show") {
		menu.appendChild(makeMenuItem("Edit inline", function() {
			inlineEditor.show(info, removeMenu);
		}));
	}

	menu.appendChild(makeMenuItem("Open " + info.tiddler, function() {
		new $tw.Story().navigateTiddler(info.tiddler); removeMenu();
	}));

	if(rangeInfo && $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking/ShowEditMenuItem", "").trim() === "show") {
		menu.appendChild(makeMenuItem("Edit at " + info.range, function() { editAndSelect(info, removeMenu); }));
	}

	if(info.caller) {
		var callerLines = info.caller.split("\n");
		for(var ci = 0; ci < callerLines.length; ci++) {
			var callerTitle = callerLines[ci].replace(/^\u2190\s*/, "").trim();
			if(callerTitle && callerTitle !== info.tiddler) {
				(function(title) {
					menu.appendChild(makeMenuItem("Open \u2190 " + title, function() {
						new $tw.Story().navigateTiddler(title); removeMenu();
					}));
				})(callerTitle);
			}
		}
	}

	document.body.appendChild(menu);
	var menuW = menu.offsetWidth, menuH = menu.offsetHeight;
	if(menuX + menuW > window.innerWidth) menuX = Math.max(0, menuX - menuW);
	if(menuY + menuH > window.innerHeight) menuY = Math.max(0, menuY - menuH);
	menu.style.left = menuX + "px";
	menu.style.top = menuY + "px";

	closeMenu = function(e) { if(!menu.contains(e.target)) removeMenu(); };
	var menuHovered = false;
	menu.addEventListener("mouseenter", function() { menuHovered = true; });
	menu.addEventListener("mouseleave", function() { menuHovered = false; });
	closeOnEscape = function(e) { if(e.key === "Escape" && menuHovered) removeMenu(); };
	setTimeout(function() {
		document.addEventListener("click", closeMenu, true);
		document.addEventListener("keydown", closeOnEscape, true);
	}, 0);
}

exports.show = show;
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/inline-editor.js":{"title":"$:/plugins/wikilabs/devtools/inline-editor.js","text":"/*\
title: $:/plugins/wikilabs/devtools/inline-editor.js
type: application/javascript
module-type: library

Inline editor: floating popup for direct wikitext editing (hidden by default).

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var el = utils.el;
var sharedState = utils.state;

function show(info, removeMenu) {
	var sourceText = $tw.wiki.getTiddlerText(info.tiddler, "");
	var snippet = sourceText.substring(info.charStart, info.charEnd);
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: "$:/temp/sourcepos/edit", text: snippet,
		"source-tiddler": info.tiddler, "source-start": String(info.charStart),
		"source-end": String(info.charEnd), "source-pos": info.raw
	}));
	if(removeMenu) removeMenu();

	var existingEditor = document.getElementById("sourcepos-inline-editor");
	if(existingEditor) existingEditor.remove();

	var layoutTitle = "$:/temp/sourcepos/editor-layout";
	var editorLayout = $tw.wiki.getTiddler(layoutTitle);
	var elF = editorLayout ? editorLayout.fields : {};
	var popupW = Math.max(300, parseInt(elF.width, 10) || 500);
	var popupH = Math.max(150, parseInt(elF.height, 10) || 300);

	var popup = el("div", "wltc-panel");
	popup.id = "sourcepos-inline-editor";
	popup.style.width = popupW + "px";
	popup.style.height = popupH + "px";

	var popupHeader = el("div", "wltc-panel-header");
	popupHeader.style.fontSize = "12px";
	popupHeader.appendChild(el("span", null, info.raw));
	var popCloseBtn = el("span", "wltc-btn-close", "\u2715");
	popCloseBtn.addEventListener("click", function() { popup.remove(); });
	popupHeader.appendChild(popCloseBtn);
	popup.appendChild(popupHeader);

	var editorArea = document.createElement("textarea");
	editorArea.value = snippet;
	editorArea.className = "wltc-editor-textarea";
	popup.appendChild(editorArea);

	var btnBar = el("div", "wltc-editor-btnbar");
	var cancelBtn = document.createElement("button");
	cancelBtn.textContent = "Cancel";
	cancelBtn.className = "wltc-editor-btn-cancel";
	cancelBtn.addEventListener("click", function() { popup.remove(); });
	btnBar.appendChild(cancelBtn);
	var applyBtn = document.createElement("button");
	applyBtn.textContent = "Apply";
	applyBtn.className = "wltc-editor-btn-apply";
	applyBtn.addEventListener("click", function() {
		var tiddler = $tw.wiki.getTiddler(info.tiddler);
		if(tiddler) {
			var fullText = tiddler.fields.text || "";
			$tw.wiki.addTiddler(new $tw.Tiddler(tiddler,
				{ text: fullText.substring(0, info.charStart) + editorArea.value + fullText.substring(info.charEnd) },
				$tw.wiki.getModificationFields()));
		}
		popup.remove();
	});
	btnBar.appendChild(applyBtn);
	popup.appendChild(btnBar);

	var resizeHandle = el("div", "wltc-panel-resize");
	resizeHandle.appendChild(el("div", "wltc-panel-grip"));
	popup.appendChild(resizeHandle);
	document.body.appendChild(popup);

	var rect = info.element.getBoundingClientRect();
	var left = Math.max(4, Math.min(rect.left, window.innerWidth - popupW - 4));
	var top = rect.bottom + 4;
	if(top + popupH > window.innerHeight) top = Math.max(4, rect.top - popupH - 4);
	popup.style.left = left + "px";
	popup.style.top = top + "px";

	utils.makeDraggable(popupHeader, popup, {
		ignore: function(e) { return e.target === popCloseBtn; }
	});
	utils.makeResizable(resizeHandle, popup, {
		onStart: function() { sharedState.isResizing = true; },
		onEnd: function() {
			sharedState.isResizing = false;
			var existing = $tw.wiki.getTiddler(layoutTitle);
			var ef = existing ? existing.fields : { title: layoutTitle };
			$tw.wiki.addTiddler(new $tw.Tiddler(ef, { title: layoutTitle, width: String(popup.offsetWidth), height: String(popup.offsetHeight) }));
		}
	});

	editorArea.focus();
	var onKeydown = function(e) {
		if(e.key === "Escape") { popup.remove(); document.removeEventListener("keydown", onKeydown, true); }
		else if(e.key === "Enter" && e.ctrlKey) { e.preventDefault(); applyBtn.click(); document.removeEventListener("keydown", onKeydown, true); }
	};
	document.addEventListener("keydown", onKeydown, true);
}

exports.show = show;
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/source-viewer.js":{"title":"$:/plugins/wikilabs/devtools/source-viewer.js","text":"/*\
title: $:/plugins/wikilabs/devtools/source-viewer.js
type: application/javascript
module-type: library

Source Viewer: a floating, draggable, resizable modal that accumulates
source code entries from data-source-pos right-click actions.

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var el = utils.el;
var sharedState = utils.state;

var MAX_SOURCE_ENTRIES = 100;
var viewer = null;
var entries = [];
var snippetMap = {};

function getLayout() {
	var s = sharedState.viewerLayout;
	return {
		width: s.width || 600, height: s.height || 400,
		left: s.left !== undefined ? s.left : -1,
		top: s.top !== undefined ? s.top : 60
	};
}

function saveLayout(props) {
	for(var k in props) sharedState.viewerLayout[k] = parseInt(props[k], 10);
}

function clearAllHighlights() {
	var headers = getAllHeaders();
	for(var i = 0; i < headers.length; i++) {
		if(headers[i]._unhighlightOrigin) headers[i]._unhighlightOrigin();
	}
}

function getOrCreate() {
	if(viewer && document.body.contains(viewer)) return viewer;

	viewer = el("div", "wltc-panel");
	viewer.id = "sourcepos-source-viewer";

	var layout = getLayout();
	viewer.style.width = Math.max(300, layout.width) + "px";
	viewer.style.height = Math.max(150, layout.height) + "px";
	if(layout.left >= 0) {
		viewer.style.left = layout.left + "px";
	} else {
		viewer.style.right = "20px";
	}
	viewer.style.top = layout.top + "px";

	// Header
	var header = el("div", "wltc-panel-header");
	header.appendChild(el("span", null, "Source Viewer"));

	var headerBtns = el("span", "wltc-btn-group");
	var clearBtn = el("span", "wltc-btn-clear", "Clear");
	clearBtn.addEventListener("click", function() {
		clearAllHighlights();
		entries = [];
		snippetMap = {};
		var c = viewer.querySelector(".sourcepos-viewer-content");
		if(c) c.innerHTML = "";
	});
	var closeBtn = el("span", "wltc-btn-close", "\u2715");
	closeBtn.addEventListener("click", function() {
		clearAllHighlights();
		viewer.remove();
	});
	headerBtns.appendChild(clearBtn);
	headerBtns.appendChild(closeBtn);
	header.appendChild(headerBtns);
	viewer.appendChild(header);

	// Content
	var content = el("div", "sourcepos-viewer-content wltc-panel-content");
	viewer.appendChild(content);

	// Resize handle
	var resizeHandle = el("div", "wltc-panel-resize");
	resizeHandle.appendChild(el("div", "wltc-panel-grip"));
	viewer.appendChild(resizeHandle);
	document.body.appendChild(viewer);

	// Drag & resize
	utils.makeDraggable(header, viewer, {
		ignore: function(e) { return e.target === closeBtn || e.target === clearBtn; },
		onStart: function() { viewer.style.right = "auto"; },
		onEnd: function() {
			saveLayout({ left: String(parseInt(viewer.style.left, 10)), top: String(parseInt(viewer.style.top, 10)) });
		}
	});
	utils.makeResizable(resizeHandle, viewer, {
		onEnd: function() {
			saveLayout({ width: String(viewer.offsetWidth), height: String(viewer.offsetHeight) });
		}
	});

	return viewer;
}

// Extract snippet and procedure name from source info
function getSnippetInfo(info) {
	var sourceText = $tw.wiki.getTiddlerText(info.tiddler, "");
	if(isNaN(info.charStart) || isNaN(info.charEnd) || info.charEnd <= info.charStart) {
		return { snippet: "(no char range available)", procName: "", key: info.tiddler + ":no-range" };
	}
	var textBefore = sourceText.substring(0, info.charStart);
	var defMatch = textBefore.match(/[\s\S]*\\(procedure|define|widget|function)\s+([^\s(]+)/);
	if(defMatch) {
		var defStart = textBefore.lastIndexOf("\\" + defMatch[1]);
		var endIdx = sourceText.indexOf("\\end", info.charEnd);
		var defEnd = (endIdx !== -1) ? endIdx + 4 : sourceText.length;
		return {
			snippet: sourceText.substring(defStart, defEnd),
			procName: defMatch[2],
			key: info.tiddler + ":" + defStart + "-" + defEnd
		};
	}
	return {
		snippet: sourceText.substring(info.charStart, info.charEnd),
		procName: "",
		key: info.tiddler + ":" + info.charStart + "-" + info.charEnd
	};
}

// Create a header row for an entry
function createHeaderRow(info, procName, editAtPosition) {
	var sourceElement = info.element;
	var row = el("div", "wltc-entry-header");
	row._sourceElement = sourceElement;

	// Blink/highlight logic
	var blinkTimer = null;
	row._highlightOrigin = function() {
		if(!sourceElement || !document.body.contains(sourceElement)) return;
		if(blinkTimer) { clearTimeout(blinkTimer); blinkTimer = null; }
		sourceElement.classList.remove("sourcepos-highlight-blink", "sourcepos-highlight-origin");
		var count = 0;
		(function doBlink() {
			if(count < 6) {
				sourceElement.classList.toggle("sourcepos-highlight-blink");
				count++;
				blinkTimer = setTimeout(doBlink, 150);
			} else {
				sourceElement.classList.remove("sourcepos-highlight-blink");
				sourceElement.classList.add("sourcepos-highlight-origin");
				blinkTimer = null;
			}
		})();
	};
	row._unhighlightOrigin = function() {
		if(blinkTimer) { clearTimeout(blinkTimer); blinkTimer = null; }
		if(sourceElement) {
			sourceElement.classList.remove("sourcepos-highlight-origin", "sourcepos-highlight-blink");
		}
	};

	// Label
	var text = info.raw;
	if(procName) text += "  \u2014 " + procName;
	if(info.context) text += "  \u00BB " + info.context;
	row.appendChild(el("span", null, text));

	// Buttons
	var btns = el("span", "wltc-btn-group-tight");
	if(editAtPosition && !isNaN(info.charStart) && !isNaN(info.charEnd)) {
		var editBtn = utils.makeIconBtn("wltc-btn-icon", "{{$:/core/images/edit-button}}", "Edit at " + info.range);
		editBtn.addEventListener("click", function(e) { e.stopPropagation(); editAtPosition(); });
		btns.appendChild(editBtn);
	}
	var removeBtn = el("span", "wltc-btn-remove", "\u2715");
	removeBtn.addEventListener("click", function(e) {
		e.stopPropagation();
		row._unhighlightOrigin();
		var entry = row.parentNode;
		row.remove();
		if(entry && !entry.querySelector(".sourcepos-entry-header")) {
			var idx = entries.indexOf(entry);
			if(idx !== -1) entries.splice(idx, 1);
			entry.remove();
			for(var k in snippetMap) {
				if(snippetMap[k] === entry) { delete snippetMap[k]; break; }
			}
		}
		updateAutoHighlight();
	});
	btns.appendChild(removeBtn);
	row.appendChild(btns);
	row.classList.add("sourcepos-entry-header");
	row.addEventListener("mouseenter", row._highlightOrigin);
	row.addEventListener("mouseleave", row._unhighlightOrigin);
	return row;
}

function getAllHeaders() {
	var headers = [];
	for(var i = 0; i < entries.length; i++) {
		var rows = entries[i].querySelectorAll(".sourcepos-entry-header");
		for(var j = 0; j < rows.length; j++) headers.push(rows[j]);
	}
	return headers;
}

function updateAutoHighlight() {
	var headers = getAllHeaders();
	for(var i = 0; i < headers.length; i++) {
		if(headers[i]._unhighlightOrigin) headers[i]._unhighlightOrigin();
	}
	if(headers.length === 1 && headers[0]._highlightOrigin) {
		headers[0]._highlightOrigin();
	}
}

function addEntry(info, editAtPosition) {
	var v = getOrCreate();
	var content = v.querySelector(".sourcepos-viewer-content");
	var si = getSnippetInfo(info);

	// Deduplicate: add header to existing entry
	var existing = snippetMap[si.key];
	if(existing && document.body.contains(existing)) {
		var headerRow = createHeaderRow(info, si.procName, editAtPosition);
		var codeBlock = existing.querySelector("pre");
		if(codeBlock) {
			existing.insertBefore(headerRow, codeBlock);
		} else {
			existing.appendChild(headerRow);
		}
		if(content.firstChild !== existing) {
			content.insertBefore(existing, content.firstChild);
		}
		updateAutoHighlight();
		return;
	}

	// Cap entries
	if(entries.length >= MAX_SOURCE_ENTRIES) {
		var oldest = content.lastChild;
		if(oldest) {
			var oldHeaders = oldest.querySelectorAll(".sourcepos-entry-header");
			for(var h = 0; h < oldHeaders.length; h++) {
				if(oldHeaders[h]._unhighlightOrigin) oldHeaders[h]._unhighlightOrigin();
			}
			for(var k in snippetMap) {
				if(snippetMap[k] === oldest) { delete snippetMap[k]; break; }
			}
			oldest.remove();
			entries.pop();
		}
	}

	// New entry
	var entry = el("div", "wltc-entry");
	entry.appendChild(createHeaderRow(info, si.procName, editAtPosition));
	var code = el("pre", "wltc-entry-code");
	code.textContent = si.snippet;
	entry.appendChild(code);

	if(content.firstChild) {
		content.insertBefore(entry, content.firstChild);
	} else {
		content.appendChild(entry);
	}
	entries.unshift(entry);
	snippetMap[si.key] = entry;
	updateAutoHighlight();
}

exports.addEntry = addEntry;
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/tooltip.js":{"title":"$:/plugins/wikilabs/devtools/tooltip.js","text":"/*\
title: $:/plugins/wikilabs/devtools/tooltip.js
type: application/javascript
module-type: library

Hover tooltip: shows source position info after a 400ms delay.

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var el = utils.el;
var sharedState = utils.state;

var hoverTimer = null;
var tooltip = null;

function removeTooltip() {
	if(hoverTimer) { clearTimeout(hoverTimer); hoverTimer = null; }
	if(tooltip) { tooltip.remove(); tooltip = null; }
}

function setup() {
	document.addEventListener("mouseover", function(event) {
		if(!$tw.wiki.trackSourcePositions || sharedState.isResizing) return;
		var info = utils.findSourcePos(event.target);
		if(!info) { removeTooltip(); return; }
		var mouseX = event.clientX, mouseY = event.clientY;
		removeTooltip();
		hoverTimer = setTimeout(function() {
			hoverTimer = null;
			var text = info.raw;
			var context = info.element.getAttribute("data-source-context");
			if(context) text += "  \u00BB " + context;
			if(info.caller) {
				var callerLines = info.caller.split("\n");
				var short = callerLines.filter(function(c) { return !context || c.indexOf(context) === -1; });
				if(short.length > 3) { short = short.slice(0, 3); short.push("\u2190 +" + (callerLines.length - 3) + " more"); }
				if(short.length > 0) text += "\n" + short.join("\n");
			}
			tooltip = el("div", "wltc-tooltip");
			tooltip.appendChild(el("div", "wltc-tooltip-header", text.split("\n")[0]));
			var restLines = text.split("\n").slice(1).join("\n");
			if(restLines) tooltip.appendChild(el("div", "wltc-tooltip-body", restLines));
			document.body.appendChild(tooltip);
			var rect = info.element.getBoundingClientRect();
			var tipH = tooltip.offsetHeight, tipW = tooltip.offsetWidth;
			var left = Math.max(4, Math.min(rect.left, window.innerWidth - tipW - 4));
			if(rect.top - tipH - 4 >= 0) {
				tooltip.style.left = left + "px";
				tooltip.style.top = (rect.top - tipH - 4) + "px";
			} else {
				tooltip.style.left = Math.min(mouseX + 8, window.innerWidth - tipW - 4) + "px";
				tooltip.style.top = Math.min(mouseY + 16, window.innerHeight - tipH - 4) + "px";
			}
		}, 400);
	}, true);

	document.addEventListener("mouseout", function(event) {
		if(!event.relatedTarget || !utils.findSourcePos(event.relatedTarget)) removeTooltip();
	}, true);
}

exports.setup = setup;
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/variable-inspector.js":{"title":"$:/plugins/wikilabs/devtools/variable-inspector.js","text":"/*\
title: $:/plugins/wikilabs/devtools/variable-inspector.js
type: application/javascript
module-type: library

Variable Inspector: floating panel showing all variables in scope at an element.

\*/

"use strict";

var utils = require("$:/plugins/wikilabs/devtools/utils.js");
var el = utils.el;
var bus = utils.bus;
var sharedState = utils.state;

var INSPECTOR_COLORS = [
	"rgba(100, 180, 255, 0.9)", "rgba(100, 220, 100, 0.9)",
	"rgba(255, 180, 60, 0.9)", "rgba(220, 100, 255, 0.9)",
	"rgba(255, 255, 80, 0.9)", "rgba(80, 220, 220, 0.9)"
];

var TYPE_COLORS = { widget: "#7a2a7a", fn: "#7a2a5a", proc: "#2a7a2a", macro: "#7a5a2a", def: "#2a5a7a", "var": "#555" };
var TYPE_KEYWORDS = { "var": true, "macro": true, "proc": true, "def": true, "fn": true, "widget": true };

function getNextColorIndex() {
	var idx = sharedState.colorIndex;
	sharedState.colorIndex = idx + 1;
	return idx;
}

function isInspectorLinked() { return sharedState.inspectorLinked; }
function setInspectorLinked(val) { sharedState.inspectorLinked = val; bus.emit("linked-changed", val); }
function getOpenPreviews() { return sharedState.openPreviews; }
function setOpenPreviews(obj) { sharedState.openPreviews = obj; bus.emit("previews-changed", obj); }

function getInspectorLayout() {
	var s = sharedState.inspectorLayout;
	return { width: Math.max(300, s.width || 600), height: Math.max(150, s.height || 350), left: s.left, top: s.top };
}

function saveInspectorLayout(props) {
	for(var k in props) sharedState.inspectorLayout[k] = parseInt(props[k], 10);
	bus.emit("layout-changed", sharedState.inspectorLayout);
}

function getVarType(v) {
	if(v.isWidget) return "widget";
	if(v.isFunction) return "fn";
	if(v.isProcedure) return "proc";
	if(v.isMacro) return "macro";
	if(v.params) return "def";
	return "var";
}

function evaluateMacroBody(body, varsArray) {
	var varMap = Object.create(null);
	for(var i = 0; i < varsArray.length; i++) {
		if(varsArray[i].value !== undefined) varMap[varsArray[i].name] = String(varsArray[i].value);
	}
	var frag = document.createDocumentFragment();
	var lastIndex = 0, re = /\$\(([^)]+)\)\$/g, m;
	while((m = re.exec(body)) !== null) {
		if(m.index > lastIndex) frag.appendChild(document.createTextNode(body.substring(lastIndex, m.index)));
		var span = document.createElement("span");
		if(varMap[m[1]] !== undefined) {
			span.textContent = varMap[m[1]];
			span.className = "wltc-subst-match";
		} else {
			span.textContent = "$(" + m[1] + ")$";
			span.className = "wltc-subst-missing";
			span.title = m[1] + " (not in scope)";
		}
		frag.appendChild(span);
		lastIndex = re.lastIndex;
	}
	if(lastIndex < body.length) frag.appendChild(document.createTextNode(body.substring(lastIndex)));
	return frag;
}

function show(vars, anchorX, anchorY, originElement, widget) {
	var layout = getInspectorLayout();
	var colorIdx = getNextColorIndex() % INSPECTOR_COLORS.length;
	var highlightColorClass = "sourcepos-highlight-color-" + colorIdx;
	var panelColor = INSPECTOR_COLORS[colorIdx];
	var existingPanels = document.querySelectorAll(".sourcepos-var-inspector");
	var offsetN = existingPanels.length;

	var panel = el("div", "sourcepos-var-inspector wltc-panel");
	panel.style.zIndex = 100001 + offsetN;
	panel.style.width = layout.width + "px";
	panel.style.height = layout.height + "px";
	panel.style.borderTop = "3px solid " + panelColor;

	// Header
	var header = el("div", "wltc-panel-header");
	var colorDot = el("span", "wltc-color-dot");
	colorDot.style.background = panelColor;
	header.appendChild(colorDot);
	var headerLabel = el("span", null, "Variables in scope (" + vars.length + ")");

	// Origin tracking
	var originSourcePos = originElement && originElement.getAttribute("data-source-pos");
	var originSourceStart = originElement && originElement.getAttribute("data-source-start");
	var originSourceContext = originElement && (originElement.getAttribute("data-source-context") || "");
	var originSourceCaller = originElement && (originElement.getAttribute("data-source-caller") || "");
	var originTagName = originElement && originElement.tagName;
	var disconnected = false;
	var disconnectedBadge = el("span", "wltc-disconnected-badge", " \u26A0 disconnected");

	function setDisconnected(val) {
		disconnected = val;
		colorDot.style.opacity = val ? "0.3" : "1";
